class LanguageModel:
    def __init__(self, train_data, vocab_size):
        self.train_data = train_data
        self.vocab_size = vocab_size
        self.word_counts = Counter()
        self.word_probabilities = np.zeros((vocab_size,))

    def train(self, num_iterations=1000, learning_rate=0.1):
        for _ in range(num_iterations):
            for sentence in self.train_data:
                for word in sentence:
                    self.word_counts[word] += 1
            self.word_probabilities = np.array([count / len(self.train_data) for count in self.word_counts.values()])
            self.word_counts = Counter()

    def perplexity(self, test_data):
        total_log_likelihood = 0
        total_words = 0
        for sentence in test_data:
            for word in sentence:
                if self.word_probabilities[word] > 0:
                    total_log_likelihood -= math.log2(self.word_probabilities[word])
                total_words += 1
        return 2 ** (total_log_likelihood / total_words)

